1	import {
2	  chromium,
3	  type Browser,
4	  type BrowserContext,
5	  type Dialog,
6	  type FrameLocator,
7	  type Locator,
8	  type Page,
9	} from "@playwright/test";
10	import { normalizeLocator } from "./locator-utils.ts";
11	import type { Step, StepLocator, StepResult, TiberoConfig } from "./types.js";
12	
13	interface ExecuteStepsOptions {
14	  onStepStart?: (step: Step, stepIndex: number) => void | Promise<void>;
15	  onStepComplete?: (
16	    result: StepResult,
17	    stepIndex: number,
18	    executedStepCount: number
19	  ) => void | Promise<void>;
20	}
