22	export class PlaywrightExecutor {
23	  private browser: Browser | null = null;
24	
25	  async initialize() {
26	    this.browser = await chromium.launch({ headless: true });
27	  }
28	
29	  async close() {
30	    await this.browser?.close();
31	  }
32	
33	  async executeSteps(
34	    steps: Step[],
35	    dbConfig?: TiberoConfig,
36	    options: ExecuteStepsOptions = {}
37	  ): Promise<StepResult[]> {
38	    if (!this.browser) {
39	      throw new Error("Browser is not initialized");
40	    }
41	
42	    const context: BrowserContext = await this.browser.newContext();
43	    const initialPage = await context.newPage();
44	    const allPages: Page[] = [initialPage];
45	    const pageRef = { current: initialPage };
46	
47	    const results: StepResult[] = [];
48	    const dialogMessages: string[] = [];
49	    const dialogListener = async (dialog: Dialog) => {
50	      dialogMessages.push(`${dialog.type()}: ${dialog.message()}`);
51	      if (dialog.type() === "confirm") {
52	        await dialog.dismiss();
53	      } else {
54	        await dialog.accept();
55	      }
56	    };
57	
58	    initialPage.on("dialog", dialogListener);
59	    context.on("page", (newPage) => {
60	      allPages.push(newPage);
61	      newPage.on("dialog", dialogListener);
62	    });
63	
64	    try {
65	      for (const [stepIndex, step] of steps.entries()) {
66	        await options.onStepStart?.(step, stepIndex);
67	        const result = await this.executeStep(step, pageRef, allPages, dbConfig, dialogMessages);
68	        results.push(result);
69	        await options.onStepComplete?.(result, stepIndex, results.length);
70	
71	        if (result.status === "error") {
72	          break;
73	        }
74	      }
75	    } finally {
76	      await context.close();
77	    }
78	
79	    return results;
80	  }
81	
82	  private async executeStep(
83	    step: Step,
84	    pageRef: { current: Page },
85	    allPages: Page[],
86	    dbConfig?: TiberoConfig,
87	    dialogMessages: string[] = []
88	  ): Promise<StepResult> {
89	    const page = pageRef.current;
90	    try {
91	      let output: unknown;
92	      const dialogStartIndex = dialogMessages.length;
93	
94	      switch (step.type) {
95	        case "navigate":
96	          await page.goto(step.url, { waitUntil: "networkidle" });
97	          output = `Navigated to ${step.url}`;
98	          break;
99	        case "click": {
100	          const locator = resolveLocator(page, step.locator, step.selector);
101	          await locator.click();
102	          output = `Clicked: ${describeLocator(step.locator, step.selector)}`;
103	          break;
104	        }
105	        case "mapClick": {
106	          const locator = resolveLocator(page, step.locator, step.selector).first();
107	          const box = await locator.boundingBox();
108	
109	          if (!box) {
110	            throw new Error(
111	              `Map target not found: ${describeLocator(step.locator, step.selector)}`
112	            );
113	          }
114	
115	          await page.mouse.click(box.x + step.x, box.y + step.y);
116	          output = `Map clicked: ${describeLocator(step.locator, step.selector)} @ (${step.x}, ${step.y})`;
117	          break;
118	        }
119	        case "fill": {
120	          const locator = resolveLocator(page, step.locator, step.selector);
121	          await locator.fill(step.text);
122	          output = `Filled: ${describeLocator(step.locator, step.selector)}`;
123	          break;
124	        }
125	        case "select": {
126	          const locator = resolveLocator(page, step.locator, step.selector);
127	          await locator.selectOption(step.text);
128	          output = `Selected: ${step.text}`;
129	          break;
130	        }
131	        case "wait":
132	          await page.waitForTimeout(step.milliseconds);
133	          output = `Waited ${step.milliseconds}ms`;
134	          break;
135	        case "screenshot": {
136	          const buffer = await page.screenshot({ fullPage: true });
137	          const screenshot = buffer.toString("base64");
138	          return { step, status: "passed", output: screenshot, screenshot };
139	        }
140	        case "evaluate":
141	          output = await page.evaluate((script) => eval(script), step.script);
142	          break;
143	        case "dbQuery":
144	          if (!dbConfig) {
145	            throw new Error("dbQuery step requires dbConfig");
146	          }
147	
148	          const { executeDbQuery } = await import("./tibero-executor");
149	          output = await executeDbQuery(dbConfig, step.query);
150	          break;
151	        case "switchTab": {
152	          const targetPage = allPages[step.index];
153	          if (!targetPage) {
154	            throw new Error(
155	              `탭 ${step.index}를 찾을 수 없습니다. 현재 탭 수: ${allPages.length}`
156	            );
157	          }
158	          await targetPage.waitForLoadState("domcontentloaded");
159	          pageRef.current = targetPage;
160	          output = `탭 ${step.index}로 전환 (총 ${allPages.length}개 탭)`;
161	          break;
162	        }
163	        default:
164	          throw new Error(`Unknown step type: ${(step as { type: string }).type}`);
165	      }
166	
167	      return {
168	        step,
169	        status: "passed",
170	        output: attachDialogMessages(output, dialogMessages.slice(dialogStartIndex)),
171	      };
172	    } catch (error) {
173	      return {
174	        step,
175	        status: "error",
176	        error: error instanceof Error ? error.message : String(error),
177	      };
178	    }
179	  }
180	}
181	
182	function resolveLocator(page: Page, locator?: StepLocator, legacySelector?: string): Locator {
183	  const normalized = normalizeLocator(locator, legacySelector);
184	
185	  if (!normalized) {
186	    throw new Error("Locator information is required for this step");
187	  }
188	
189	  const scope: Page | FrameLocator = normalized.frame
190	    ? page.frameLocator(normalized.frame)
191	    : page;
192	
193	  if (normalized.role) {
194	    return normalized.name
195	      ? scope.getByRole(normalized.role as Parameters<Page["getByRole"]>[0], {
196	          name: normalized.name,
197	          exact: true,
198	        })
199	      : scope.getByRole(normalized.role as Parameters<Page["getByRole"]>[0]);
200	  }
201	
202	  if (normalized.label) {
203	    return scope.getByLabel(normalized.label);
204	  }
205	
206	  if (normalized.placeholder) {
207	    return scope.getByPlaceholder(normalized.placeholder);
208	  }
209	
210	  if (normalized.text) {
211	    return scope.getByText(normalized.text);
212	  }
213	
214	  if (normalized.testId) {
215	    return scope.getByTestId(normalized.testId);
216	  }
217	
218	  if (normalized.selector) {
219	    return scope.locator(normalized.selector);
220	  }
221	
222	  throw new Error("Unable to resolve locator");
223	}
224	
225	function describeLocator(locator?: StepLocator, legacySelector?: string): string {
226	  const normalized = normalizeLocator(locator, legacySelector);
227	
228	  if (!normalized) {
229	    return "locator 없음";
230	  }
231	
232	  if (normalized.role) {
233	    return normalized.name
234	      ? `role=${normalized.role}, name=${normalized.name}`
235	      : `role=${normalized.role}`;
236	  }
237	
238	  if (normalized.label) {
239	    return `label=${normalized.label}`;
240	  }
241	
242	  if (normalized.placeholder) {
243	    return `placeholder=${normalized.placeholder}`;
244	  }
245	
246	  if (normalized.text) {
247	    return `text=${normalized.text}`;
248	  }
249	
250	  if (normalized.testId) {
251	    return `testId=${normalized.testId}`;
252	  }
253	
254	  return `legacy selector=${normalized.selector}`;
255	}
256	
257	function attachDialogMessages(output: unknown, dialogMessages: string[]): unknown {
258	  if (dialogMessages.length === 0) {
259	    return output;
260	  }
261	
262	  if (typeof output === "string") {
263	    return `${output} | Dialog accepted: ${dialogMessages.join(", ")}`;
264	  }
265	
266	  return {
267	    output,
268	    dialogs: dialogMessages,
269	  };
270	}
