12	interface RunScenarioOptions {
13	  onTestCaseStart?: (
14	    testCase: TestCase,
15	    testCaseIndex: number,
16	    totalTestCases: number
17	  ) => void | Promise<void>;
18	  onStepStart?: (
19	    testCase: TestCase,
20	    testCaseIndex: number,
21	    step: Step,
22	    stepIndex: number
23	  ) => void | Promise<void>;
24	  onStepComplete?: (
25	    testCase: TestCase,
26	    testCaseIndex: number,
27	    result: StepResult,
28	    stepIndex: number,
29	    executedStepCount: number
30	  ) => void | Promise<void>;
31	  onTestCaseComplete?: (
32	    testCase: TestCase,
33	    testCaseIndex: number,
34	    result: TestCaseResult
35	  ) => void | Promise<void>;
36	}
37	
38	async function runTestCase(
39	  testCase: TestCase,
40	  scenarioDbConfig?: TiberoConfig,
41	  options: Omit<RunScenarioOptions, "onTestCaseStart" | "onTestCaseComplete"> = {},
42	  testCaseIndex = 0
43	): Promise<TestCaseResult> {
44	  const dbConfig = testCase.dbConfig ?? scenarioDbConfig;
45	  const executor = new PlaywrightExecutor();
46	  const startedAt = Date.now();
47	
48	  try {
49	    await executor.initialize();
50	    const stepResults = await executor.executeSteps(testCase.steps, dbConfig, {
51	      onStepStart: (step, stepIndex) =>
52	        options.onStepStart?.(testCase, testCaseIndex, step, stepIndex),
53	      onStepComplete: (result, stepIndex, executedStepCount) =>
54	        options.onStepComplete?.(testCase, testCaseIndex, result, stepIndex, executedStepCount),
55	    });
56	    const hasError = stepResults.some((result) => result.status === "error");
57	
58	    return {
59	      testCaseId: testCase.id,
60	      testCaseName: testCase.name,
61	      status: hasError ? "error" : "passed",
62	      executionTime: Date.now() - startedAt,
63	      stepResults,
64	    };
65	  } finally {
66	    await executor.close();
67	  }
68	}
69	
70	export async function runScenario(
71	  scenario: Scenario,
72	  options: RunScenarioOptions = {}
73	): Promise<ScenarioResult> {
74	  const testCaseResults: TestCaseResult[] = [];
75	
76	  for (const [testCaseIndex, testCase] of scenario.testCases.entries()) {
77	    await options.onTestCaseStart?.(testCase, testCaseIndex, scenario.testCases.length);
78	    const result = await runTestCase(testCase, scenario.dbConfig, options, testCaseIndex);
79	    testCaseResults.push(result);
80	    await options.onTestCaseComplete?.(testCase, testCaseIndex, result);
81	  }
82	
83	  return {
84	    scenarioId: scenario.id,
85	    scenarioName: scenario.name,
86	    executedAt: new Date().toISOString(),
87	    testCaseResults,
88	  };
89	}
