10	function deepEqual(left: unknown, right: unknown): boolean {
11	  if (left === right) {
12	    return true;
13	  }
14	
15	  if (left == null || right == null) {
16	    return left === right;
17	  }
18	
19	  if (typeof left !== typeof right) {
20	    return false;
21	  }
22	
23	  if (typeof left !== "object" || typeof right !== "object") {
24	    return left === right;
25	  }
26	
27	  const leftKeys = Object.keys(left);
28	  const rightKeys = Object.keys(right);
29	
30	  if (leftKeys.length !== rightKeys.length) {
31	    return false;
32	  }
33	
34	  return leftKeys.every((key) =>
35	    deepEqual((left as Record<string, unknown>)[key], (right as Record<string, unknown>)[key])
36	  );
37	}
38	
39	function compareTestCase(snapshot: TestCaseResult, current: TestCaseResult): TestCaseDiff {
40	  const stepDiffs: StepDiff[] = [];
41	  const maxLength = Math.max(snapshot.stepResults.length, current.stepResults.length);
42	
43	  for (let index = 0; index < maxLength; index += 1) {
44	    const snapshotStep: StepResult | undefined = snapshot.stepResults[index];
45	    const currentStep: StepResult | undefined = current.stepResults[index];
46	    const snapshotOutput = snapshotStep?.output ?? null;
47	    const currentOutput = currentStep?.output ?? null;
48	    const isDifferent = !deepEqual(snapshotOutput, currentOutput);
49	
50	    if (isDifferent || snapshotStep?.status !== currentStep?.status) {
51	      stepDiffs.push({
52	        stepIndex: index,
53	        description: snapshotStep?.step.description ?? currentStep?.step.description,
54	        snapshotOutput,
55	        currentOutput,
56	        isDifferent,
57	        severity:
58	          snapshotStep?.status === "error" || currentStep?.status === "error"
59	            ? "critical"
60	            : "warning",
61	      });
62	    }
63	  }
64	
65	  return {
66	    testCaseId: snapshot.testCaseId,
67	    testCaseName: snapshot.testCaseName,
68	    status: stepDiffs.length === 0 ? "identical" : "different",
69	    stepDiffs,
70	  };
71	}
72	
73	export function compareWithSnapshot(
74	  snapshot: ScenarioResult,
75	  current: ScenarioResult
76	): ComparisonReport {
77	  const testCaseDiffs = snapshot.testCaseResults.map((snapshotCase) => {
78	    const currentCase = current.testCaseResults.find(
79	      (candidate) => candidate.testCaseId === snapshotCase.testCaseId
80	    );
81	
82	    if (!currentCase) {
83	      return {
84	        testCaseId: snapshotCase.testCaseId,
85	        testCaseName: snapshotCase.testCaseName,
86	        status: "error",
87	        stepDiffs: [],
88	      } satisfies TestCaseDiff;
89	    }
90	
91	    return compareTestCase(snapshotCase, currentCase);
92	  });
93	
94	  const hasDifferences = testCaseDiffs.some((diff) => diff.status !== "identical");
95	
96	  return {
97	    scenarioId: snapshot.scenarioId,
98	    snapshotCapturedAt: snapshot.executedAt,
99	    comparedAt: new Date().toISOString(),
100	    status: hasDifferences ? "different" : "identical",
101	    testCaseDiffs,
102	  };
103	}
