2	import type { NextRequest } from "next/server";
3	import {
4	  createRunProgress,
5	  markRunCompleted,
6	  markRunErrored,
7	  setRunProgress,
8	  updateRunProgress,
9	} from "@/lib/run-progress";
10	import { getScenario } from "@/lib/scenario-manager";
11	import { runScenario } from "@/lib/test-runner";
