13	export async function POST(_: NextRequest, { params }: { params: { id: string } }) {
14	  try {
15	    const scenario = getScenario(params.id);
16	
17	    if (!scenario) {
18	      return NextResponse.json({ success: false, error: "Not found" }, { status: 404 });
19	    }
20	
21	    setRunProgress(createRunProgress(scenario, params.id));
22	
23	    const result = await runScenario(scenario, {
24	      onTestCaseStart: async (testCase, testCaseIndex, totalTestCases) => {
25	        updateRunProgress(scenario.id, (current) => ({
26	          ...current,
27	          status: "running",
28	          updatedAt: new Date().toISOString(),
29	          currentTestCaseIndex: testCaseIndex + 1,
30	          currentTestCaseName: testCase.name,
31	          currentStepIndex: 0,
32	          currentStepDescription: undefined,
33	          currentTestCaseTotalSteps: testCase.steps.length,
34	          totalTestCases,
35	          message: `테스트케이스 실행 중: ${testCase.name}`,
36	        }));
37	      },
38	      onStepStart: async (testCase, _testCaseIndex, step, stepIndex) => {
39	        updateRunProgress(scenario.id, (current) => ({
40	          ...current,
41	          updatedAt: new Date().toISOString(),
42	          currentTestCaseName: testCase.name,
43	          currentStepIndex: stepIndex + 1,
44	          currentStepDescription: step.description ?? step.type,
45	          currentTestCaseTotalSteps: testCase.steps.length,
46	          message: `Step 실행 중: ${step.description ?? step.type}`,
47	        }));
48	      },
49	      onStepComplete: async () => {
50	        updateRunProgress(scenario.id, (current) => ({
51	          ...current,
52	          updatedAt: new Date().toISOString(),
53	          completedStepsOverall: Math.min(
54	            current.completedStepsOverall + 1,
55	            current.totalStepsOverall
56	          ),
57	          message: `전체 ${Math.min(
58	            current.completedStepsOverall + 1,
59	            current.totalStepsOverall
60	          )}개 step 완료`,
61	        }));
62	      },
63	    });
64	
65	    markRunCompleted(scenario.id);
66	    return NextResponse.json({ success: true, data: result });
67	  } catch (error) {
68	    markRunErrored(params.id, error instanceof Error ? error.message : String(error));
69	    return NextResponse.json({ success: false, error: String(error) }, { status: 500 });
70	  }
71	}
